      "content": "const { randomUUID } = require('node:crypto');

let tasksStore = [];

async function createTask(projectId, title) {
  const task = {
    id: randomUUID(),
    projectId,
    title,
    status: 'todo',
  };
  tasksStore.push(task);
  return task;
}

async function getTasks(projectId, status) {
  let tasks = tasksStore.filter(task => task.projectId === projectId);
  if (status) {
    tasks = tasks.filter(task => task.status === status);
  }
  return tasks;
}

async function updateTaskStatus(projectId, taskId, status) {
  const task = tasksStore.find(t => t.id === taskId && t.projectId === projectId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
}

module.exports = {
  createTask,
  getTasks,
  updateTaskStatus,
};
